import { access, mkdir, readFile, rename, rm, writeFile } from "node:fs/promises";
import { dirname, join } from "node:path";
import { homedir } from "node:os";
import { fileURLToPath } from "node:url";
import packageJson from "../../../package.json" with { type: "json" };
const TOKENJUICE_OPENCODE_EXTENSION_BASENAME = "tokenjuice.js";
const TOKENJUICE_OPENCODE_FIX_COMMAND = "tokenjuice install opencode";
function getOpenCodeConfigDir() {
    const explicit = process.env.OPENCODE_CONFIG_DIR;
    if (explicit && explicit.trim()) {
        return explicit;
    }
    const xdg = process.env.XDG_CONFIG_HOME;
    if (xdg && xdg.trim()) {
        return join(xdg, "opencode");
    }
    return join(homedir(), ".config", "opencode");
}
function getDefaultExtensionPath() {
    return join(getOpenCodeConfigDir(), "plugins", TOKENJUICE_OPENCODE_EXTENSION_BASENAME);
}
function buildOpenCodeExtensionSource(runtimeSource, config) {
    return String.raw `/**
 * tokenjuice opencode extension
 * generated by tokenjuice v${packageJson.version}
 */

${runtimeSource}

const config = ${JSON.stringify(config, null, 2)};

export default createTokenjuiceOpenCodeExtension(config);
`;
}
async function resolveOpenCodeRuntimeEntryPoint() {
    const candidates = [
        fileURLToPath(new URL("./extension/runtime.ts", import.meta.url)),
        fileURLToPath(new URL("../../../src/hosts/opencode/extension/runtime.ts", import.meta.url)),
    ];
    for (const candidate of candidates) {
        try {
            await access(candidate);
            return candidate;
        }
        catch {
            continue;
        }
    }
    throw new Error(`unable to resolve opencode runtime source entrypoint from ${candidates.join(", ")}`);
}
async function bundleOpenCodeExtensionRuntimeSource() {
    let esbuild;
    try {
        esbuild = await import("esbuild");
    }
    catch (error) {
        throw new Error(`unable to load esbuild to bundle the opencode runtime from source: ${String(error)}`);
    }
    const entryPoint = await resolveOpenCodeRuntimeEntryPoint();
    const result = await esbuild.build({
        entryPoints: [entryPoint],
        bundle: true,
        format: "esm",
        platform: "node",
        target: "node20",
        write: false,
    });
    const runtimeSource = result.outputFiles[0]?.text;
    if (!runtimeSource) {
        throw new Error("failed to bundle the opencode runtime: esbuild produced no output");
    }
    return runtimeSource;
}
async function loadOpenCodeExtensionRuntimeSource(local = false) {
    if (local) {
        return await bundleOpenCodeExtensionRuntimeSource();
    }
    const runtimeAssetUrl = new URL("./extension/runtime.js", import.meta.url);
    try {
        return await readFile(runtimeAssetUrl, "utf8");
    }
    catch (error) {
        if (error.code !== "ENOENT") {
            throw error;
        }
    }
    return await bundleOpenCodeExtensionRuntimeSource();
}
async function writeAtomically(path, content) {
    const tempPath = `${path}.tmp`;
    await writeFile(tempPath, content, { encoding: "utf8", mode: 0o600 });
    await rename(tempPath, path);
}
export async function installOpenCodeExtension(extensionPath = getDefaultExtensionPath(), options = {}) {
    const runtimeConfig = {};
    const runtimeSource = await loadOpenCodeExtensionRuntimeSource(Boolean(options.local));
    const extensionSource = buildOpenCodeExtensionSource(runtimeSource, runtimeConfig);
    await mkdir(dirname(extensionPath), { recursive: true });
    let backupPath;
    try {
        const existing = await readFile(extensionPath, "utf8");
        backupPath = `${extensionPath}.bak`;
        await writeFile(backupPath, existing, "utf8");
    }
    catch (error) {
        if (error.code !== "ENOENT") {
            throw error;
        }
    }
    await writeAtomically(extensionPath, extensionSource);
    return {
        extensionPath,
        ...(backupPath ? { backupPath } : {}),
    };
}
export async function doctorOpenCodeExtension(extensionPath = getDefaultExtensionPath()) {
    let source;
    try {
        source = await readFile(extensionPath, "utf8");
    }
    catch (error) {
        if (error.code === "ENOENT") {
            return {
                extensionPath,
                status: "disabled",
                issues: [],
                fixCommand: TOKENJUICE_OPENCODE_FIX_COMMAND,
                checkedPaths: [],
            };
        }
        return {
            extensionPath,
            status: "broken",
            issues: [`tokenjuice opencode extension could not be read: ${String(error)}`],
            fixCommand: TOKENJUICE_OPENCODE_FIX_COMMAND,
            checkedPaths: [extensionPath],
        };
    }
    const issues = [];
    if (!source.includes("generated by tokenjuice v") ||
        !source.includes("createTokenjuiceOpenCodeExtension")) {
        issues.push("installed opencode extension does not look like a tokenjuice-generated extension");
    }
    return {
        extensionPath,
        status: issues.length > 0 ? "warn" : "ok",
        issues,
        fixCommand: TOKENJUICE_OPENCODE_FIX_COMMAND,
        checkedPaths: [extensionPath],
    };
}
export async function uninstallOpenCodeExtension(extensionPath = getDefaultExtensionPath()) {
    try {
        await rm(extensionPath);
        return { extensionPath, removed: true };
    }
    catch (error) {
        if (error.code === "ENOENT") {
            return { extensionPath, removed: false };
        }
        throw error;
    }
}
